const item = $input.first().json;
const credentials = typeof item.credentials === 'string' ? JSON.parse(item.credentials) : (item.credentials || {});
const settings = typeof item.settings === 'string' ? JSON.parse(item.settings) : (item.settings || {});

const accessToken = credentials.access_token;
const authorUrn = settings.author_urn || credentials.person_urn;

if (!accessToken || !authorUrn) {
  throw new Error('LinkedIn credentials not configured. Connect LinkedIn in Admin > Social Content.');
}

// Build the full post text with hashtags
let fullText = item.post_text || '';
if (item.cta_text) fullText += '\n\n' + item.cta_text;
if (item.cta_url) fullText += '\n' + item.cta_url;
const hashtags = typeof item.hashtags === 'string' ? JSON.parse(item.hashtags || '[]') : (item.hashtags || []);
if (hashtags.length > 0) {
  fullText += '\n\n' + hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ');
}

return [{ json: {
  content_id: item.id,
  access_token: accessToken,
  author_urn: authorUrn,
  full_text: fullText,
  image_url: item.image_url,
  has_image: !!item.image_url
} }];

